Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` without opening a real port. Pair it with the MCP C# SDK client pointing at that client.

Here's the pattern:

```csharp
// 1. Add these packages to your test project:
//    Microsoft.AspNetCore.Mvc.Testing
//    ModelContextProtocol  (the C# MCP SDK)

// 2. Create a test fixture
public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly WebApplicationFactory<Program> _factory;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _factory = factory;
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        // WebApplicationFactory gives you an in-memory HttpClient
        var httpClient = _factory.CreateClient();

        // Use the MCP SDK's SseClientTransport (or StreamableHttp transport)
        // pointed at the in-memory client
        var options = new SseClientTransportOptions
        {
            Endpoint = new Uri("http://localhost/sse"),  // path your server listens on
            HttpClient = httpClient,                     // key: inject the in-memory client
        };

        await using var transport = new SseClientTransport(options);
        await using var mcpClient = await McpClientFactory.CreateAsync(transport);

        // Assert server capabilities from the initialization response
        Assert.NotNull(mcpClient.ServerCapabilities);
        Assert.NotNull(mcpClient.ServerCapabilities.Tools);
    }

    [Fact]
    public async Task ListTools_ReturnsExpectedTools()
    {
        var httpClient = _factory.CreateClient();
        var options = new SseClientTransportOptions
        {
            Endpoint = new Uri("http://localhost/sse"),
            HttpClient = httpClient,
        };

        await using var transport = new SseClientTransport(options);
        await using var mcpClient = await McpClientFactory.CreateAsync(transport);

        var tools = await mcpClient.ListToolsAsync();

        Assert.Contains(tools, t => t.Name == "my_tool");
    }

    [Fact]
    public async Task CallTool_ReturnsCorrectResult()
    {
        var httpClient = _factory.CreateClient();
        var options = new SseClientTransportOptions
        {
            Endpoint = new Uri("http://localhost/sse"),
            HttpClient = httpClient,
        };

        await using var transport = new SseClientTransport(options);
        await using var mcpClient = await McpClientFactory.CreateAsync(transport);

        var result = await mcpClient.CallToolAsync(
            "my_tool",
            new Dictionary<string, object?> { ["input"] = "test" });

        Assert.False(result.IsError);
        Assert.NotEmpty(result.Content);
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your entire middleware pipeline in-process — no port, no network.
- Inject the factory's `HttpClient` into the MCP SDK transport via the `HttpClient` property so all MCP traffic flows through the in-memory test server.
- If your server uses the newer **Streamable HTTP** transport instead of SSE, use `StreamableHttpClientTransport` with the same `HttpClient` injection pattern.
- You can override DI services (databases, external APIs) using `_factory.WithWebHostBuilder(b => b.ConfigureServices(...))` as with any ASP.NET Core integration test.
